/**
 * Stale-snapshot guard regression test.
 *
 * If `sessions.json` on disk has a HIGHER epoch than what we last loaded
 * (e.g. cloud sync / antivirus restored a newer file under a running
 * gateway, or the primary was repaired manually), saveNow() must refuse to
 * write — otherwise we'd clobber newer state with stale in-memory data.
 */
import { describe, it, beforeEach } from "vitest";
import assert from "node:assert/strict";
import path from "node:path";
import { SessionStore, type PersistedSession } from "../../src/server/agent/session-store.ts";
import { createMemFs, type MemFs } from "../harness/mem-fs.ts";

type SessionStoreMemFs = MemFs & {
	openSync(file: string, flags: string): number;
	fsyncSync(fd: number): void;
	closeSync(fd: number): void;
};

function createSessionStoreMemFs(): SessionStoreMemFs {
	const memfs = createMemFs() as SessionStoreMemFs;
	let nextFd = 3;
	const fds = new Map<number, string>();
	const writeFileSync = memfs.writeFileSync.bind(memfs);
	memfs.openSync = (file: string) => {
		const fd = nextFd++;
		fds.set(fd, file);
		return fd;
	};
	(memfs as any).writeFileSync = (target: string | number, data: string | NodeJS.ArrayBufferView, encoding?: BufferEncoding) => {
		if (typeof target === "number") {
			const file = fds.get(target);
			if (!file) throw Object.assign(new Error(`EBADF: bad file descriptor, write '${target}'`), { code: "EBADF" });
			return writeFileSync(file, data, encoding as any);
		}
		return writeFileSync(target, data, encoding as any);
	};
	memfs.fsyncSync = () => {};
	memfs.closeSync = (fd: number) => { fds.delete(fd); };
	return memfs;
}

const stateDir = path.join("/state", "session-store-stale");
const STORE_FILE = path.join(stateDir, "sessions.json");
let memfs: SessionStoreMemFs;

function makeSession(id: string): PersistedSession {
	return {
		id,
		title: `Session ${id}`,
		cwd: "/tmp/test",
		agentSessionFile: `/tmp/test/${id}.jsonl`,
		createdAt: Date.now(),
		lastActivity: Date.now(),
	};
}

describe("SessionStore stale-snapshot guard", () => {
	beforeEach(() => {
		memfs = createSessionStoreMemFs();
	});

	it("refuses to save when on-disk epoch is newer than loaded epoch", () => {
		// Start fresh, no sessions.json on disk.
		const store = new SessionStore(stateDir, memfs);
		assert.equal(store.getLoadedEpoch(), 0);

		// External writer puts a v2 file with epoch 50 after we constructed.
		const externalPayload = {
			version: 2,
			epoch: 50,
			sessions: [{
				id: "external-1",
				title: "External",
				cwd: "/external",
				agentSessionFile: "/external/a.jsonl",
				createdAt: Date.now(),
				lastActivity: Date.now(),
			}],
		};
		memfs.writeFileSync(STORE_FILE, JSON.stringify(externalPayload, null, 2), "utf-8");

		// Capture console.error
		const errors: string[] = [];
		const origErr = console.error;
		console.error = (...args: unknown[]) => { errors.push(args.map(String).join(" ")); };

		try {
			// Trigger a save with an in-memory put.
			store.put(makeSession("s-stale"));

			// On-disk file must be unchanged (still epoch 50, external-1).
			const onDisk = JSON.parse(memfs.readFileSync(STORE_FILE, "utf-8"));
			assert.equal(onDisk.epoch, 50, "on-disk epoch must remain 50 — write refused");
			assert.equal(onDisk.sessions.length, 1);
			assert.equal(onDisk.sessions[0].id, "external-1");
		} finally {
			console.error = origErr;
		}

		assert.ok(errors.some(e => /REFUSING to save/.test(e)), `expected REFUSING-to-save log line, got: ${errors.join("\n")}`);
		assert.equal(store.isStaleGuardTripped(), true);
		assert.equal(store.getWrittenEpoch(), 0, "no write succeeded");

		// Subsequent put — still no write.
		const errsBefore = errors.length;
		store.put(makeSession("s-stale-2"));
		const onDisk2 = JSON.parse(memfs.readFileSync(STORE_FILE, "utf-8"));
		assert.equal(onDisk2.epoch, 50, "second put still must not overwrite");
		assert.equal(errors.length, errsBefore, "guard latched — no further error spam");
	});

	it("refuses a stale first write from a second store instance", () => {
		const staleStore = new SessionStore(stateDir, memfs);
		const winningStore = new SessionStore(stateDir, memfs);

		winningStore.put(makeSession("winner"));
		const winningRaw = memfs.readFileSync(STORE_FILE, "utf-8");

		const origErr = console.error;
		console.error = () => {};
		try {
			staleStore.put(makeSession("stale-writer"));
		} finally {
			console.error = origErr;
		}

		assert.equal(staleStore.isStaleGuardTripped(), true);
		assert.equal(staleStore.getWrittenEpoch(), 0);
		assert.equal(memfs.readFileSync(STORE_FILE, "utf-8"), winningRaw, "stale writer must not alter the winner's bytes");
	});

	it("does NOT trip the guard when on-disk epoch matches what we wrote earlier", () => {
		// Write a few sessions, flush, then put more — no external rewrite.
		const store = new SessionStore(stateDir, memfs);
		store.put(makeSession("s1"));
		store.put(makeSession("s2"));
		store.put(makeSession("s3"));
		store.put(makeSession("s4"));
		store.put(makeSession("s5"));
		store.flush();

		const after5 = JSON.parse(memfs.readFileSync(STORE_FILE, "utf-8"));
		assert.equal(after5.epoch, 5);
		assert.equal(store.isStaleGuardTripped(), false);
		assert.equal(store.getWrittenEpoch(), 5);

		// Another put — epoch should advance, guard should not trip.
		store.put(makeSession("s6"));
		const after6 = JSON.parse(memfs.readFileSync(STORE_FILE, "utf-8"));
		assert.equal(after6.epoch, 6);
		assert.equal(store.isStaleGuardTripped(), false);
	});
});
